import { Component, OnInit } from "@angular/core";
import { SearchResult } from "../../Models/References/SearchResult";
import { LoanApplicationsService } from "src/app/core/services/loan-applications.service";
import { AlertService } from "src/app/core/services/alert.service";
import { GetLoanApplicationResponse } from "../../Models/Loan/GetLoanApplication";
import { th } from "date-fns/locale";
import { ClientService } from "src/app/core/services/client.service";
import { ClientInfo, CosignersInfo } from "../../Models/Client/ClientInfo";
import { OfficersVisitsWorkFlow } from "../../Models/Officer/OfficerVisitsWorkFlow";
import { JobUserDocs } from "../../Models/Users/JobUserDocs";

@Component({
  selector: "app-remove-application",
  templateUrl: "./remove-application.page.html",
  styleUrls: ["./remove-application.page.scss"],
})
export class RemoveApplicationPage implements OnInit {
  showLoader: boolean = false;
  isSearching: boolean = true;

  applicationInfo: GetLoanApplicationResponse;
  clientInfo: ClientInfo;
  selectedCosigners: CosignersInfo[] = [];
  cosignerParameterForClientInfo: ClientInfo;
  lastSteps: OfficersVisitsWorkFlow[];
  currentStep: JobUserDocs[];
  openModal: boolean = false;

  constructor(
    private loanApplicationService: LoanApplicationsService,
    public alertService: AlertService,
    private clientService: ClientService
  ) {}

  ngOnInit() {}

  async clientSelected(event: SearchResult) {
    this.showLoader = true;
    await this.loanApplicationService
      .getApplicationKey(event.application_key)
      .then(async (res) => {
        this.applicationInfo = res as GetLoanApplicationResponse;
        await this.clientService
          .getClientByClientKey(res.clientKey)
          .then(async (client) => {
            this.clientInfo = client as ClientInfo;
            this.isSearching = false;
            this.cosignerParameterForClientInfo = {
              org_code: client.org_code,
              client_code: client.org_branch_code + "/" + client.client_code,
              nation_id: client.nation_id,
            };
            this.selectedCosigners =
              await this.loanApplicationService.getLoanApplicationCosigners(
                res.applicationKey.toString()
              );
            this.currentStep = await this.loanApplicationService.getJobUsersDoc(
              res.applicationKey.toString()
            );
            this.lastSteps = await this.loanApplicationService.getLastSteps(
              res.applicationKey.toString()
            );
          });
      })
      .catch((err) => {
        this.alertService.showAlertError(err.error, false);
        console.log("Error fetching application key:", err);
      })
      .finally(() => {
        this.showLoader = false;
      });
  }

  backToSearch() {
    this.isSearching = true;
    this.applicationInfo = null;
    this.clientInfo = null;
    this.selectedCosigners = [];
    this.cosignerParameterForClientInfo = null;
    this.lastSteps = [];
    this.currentStep = [];
    this.openModal = false;
  }

  async removeApplication() {
    if (await this.alertService.SaveAlert("هل أنت متأكد من حذف الطلب؟")) {
      this.showLoader = true;
      await this.loanApplicationService
        .deleteApplication(
          this.applicationInfo.applicationKey.toString(),
          this.applicationInfo.uuc.toString(),
          this.clientInfo.uuc.toString()
        )
        .toPromise()
        .then(() => {
          this.showLoader = false;
          this.alertService.showAlertConfirm("تم حذف الطلب بنجاح", true);
        })
        .catch((error) => {
          this.showLoader = false;
          this.alertService.showAlertError(
            "حدث خطأ أثناء حذف الطلب: " + error.error,
            false
          );
          console.error("Error removing application:", error);
        });
    }
  }
}
